import { HTMLAttributes, ReactNode } from 'react';
import { TestComponentProps } from 'src/types/test-component';
export interface FooterSocialLink {
    label: ReactNode;
    href: string;
    icon?: ReactNode;
}
export interface FooterNavItem {
    label?: ReactNode;
    href?: string;
    onClick?: (e: React.MouseEvent) => void;
    external?: boolean;
    disabled?: boolean;
}
export interface FooterColumn {
    title?: ReactNode;
    items?: FooterNavItem[];
}
export interface FooterProps extends HTMLAttributes<HTMLElement>, TestComponentProps {
    /** Логотип бренда и подпись  */
    brand?: ReactNode;
    /** Соцсети */
    socials?: FooterSocialLink[];
    /** Колонки с навигацией (левая/правая) */
    columns?: [FooterColumn?, FooterColumn?];
    /** Копирайт, политика конфиденциальности */
    copyrightText?: ReactNode;
    privacyHref?: string;
    privacyLabel?: string;
}
